from spyne import Application, rpc, ServiceBase, Integer, Float, Unicode
from spyne.protocol.soap import Soap11
from spyne.protocol.soap.soap import SoapFault
from spyne.model.primitive import Integer, Unicode
from spyne.model.complex import ComplexModel
from spyne.service import ServiceBase
from spyne import server
from wsgiref.simple_server import make_server

class Account(ComplexModel):
    account_number = Unicode
    account_holder = Unicode
    balance = Float

accounts_db = {
    '123456': Account(account_number='123456', account_holder='John Doe', balance=1000.0),
    '654321': Account(account_number='654321', account_holder='Jane Smith', balance=2000.0),
}

class FinancialService(ServiceBase):
    @rpc(Unicode, _returns=Float, _soap_action='getBalance')
    def getBalance(self, account_number):
        account = accounts_db.get(account_number)
        if account:
            return account.balance
        raise SoapFault('AccountNotFound', f'Account {account_number} not found.')

    @rpc(Unicode, Float, _returns=Unicode, _soap_action='transferFunds')
    def transferFunds(self, from_account, amount):
        from_account_info = accounts_db.get(from_account)
        if from_account_info and from_account_info.balance >= amount:
            from_account_info.balance -= amount
            return f'Transferred {amount} from {from_account}'
        raise SoapFault('InsufficientFunds', 'Insufficient funds for transfer.')

    @rpc(Unicode, _returns=Account, _soap_action='getAccountInfo')
    def getAccountInfo(self, account_number):
        account = accounts_db.get(account_number)
        if account:
            return account
        raise SoapFault('AccountNotFound', f'Account {account_number} not found.')

application = Application([
    FinancialService
], tns='spyne.examples.financial',
   in_protocol=Soap11(validator='lxml'),
   out_protocol=Soap11()
)

